def build_wt_dict():
    embedding_model = ESM_embedding()
    wt_dict = {}

    for gfp_name, sequence in GFP_WT.items():
        # 提取 [500, 1152] 的 numpy 数组
        emb_numpy = embedding_model.embedding_sequence(sequence)
        # 转为 PyTorch Tensor
        wt_dict[gfp_name] = torch.from_numpy(emb_numpy).float()
        print(f" {gfp_name} 特征提取完毕，形状: {wt_dict[gfp_name].shape}")

    torch.save(wt_dict, "wt_embeddings_dict.pt")
    print("saved to wt_embeddings_dict.pt")


if __name__ == "__main__":
    build_wt_dict()
